local function sanitize_command(cmd)
    if not cmd or cmd == "" then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say('{"error": "No command provided"}')
        ngx.exit(ngx.HTTP_BAD_REQUEST)
        return nil
    end

    local allowed_commands = {
        ["disk_usage"] = "df -h",
        ["memory_info"] = "free -m",
        ["uptime"] = "uptime",
        ["load_average"] = "cat /proc/loadavg",
        ["hostname"] = "hostname",
        ["date"] = "date",
        ["cpu_info"] = "lscpu",
        ["network_interfaces"] = "ip -br addr show",
        ["process_count"] = "ps aux --no-heading | wc -l",
        ["kernel_version"] = "uname -r",
        ["filesystem_usage"] = "df -Th",
        ["swap_info"] = "swapon --show",
        ["logged_in_users"] = "who",
        ["service_status_nginx"] = "systemctl is-active nginx",
        ["service_status_sshd"] = "systemctl is-active sshd",
        ["dns_resolv"] = "cat /etc/resolv.conf",
        ["top_processes"] = "ps aux --sort=-%mem | head -11",
        ["disk_io"] = "iostat -x 1 1",
        ["open_ports"] = "ss -tlnp",
        ["system_logs_recent"] = "journalctl --no-pager -n 20",
    }

    local resolved = allowed_commands[cmd]
    if not resolved then
        ngx.status = ngx.HTTP_FORBIDDEN
        local available = {}
        for k, _ in pairs(allowed_commands) do
            available[#available + 1] = k
        end
        table.sort(available)
        ngx.say('{"error": "Command not allowed", "available_commands": ' .. require("cjson").encode(available) .. '}')
        ngx.exit(ngx.HTTP_FORBIDDEN)
        return nil
    end

    return resolved
end

local function execute_command(shell_cmd)
    local handle = io.popen(shell_cmd .. " 2>&1", "r")
    if not handle then
        return nil, "Failed to execute command"
    end

    local result = handle:read("*a")
    local ok, exit_type, exit_code = handle:close()

    return {
        output = result,
        success = (exit_type == "exit" and exit_code == 0),
        exit_code = exit_code or -1
    }
end

local function check_auth()
    local auth_header = ngx.var.http_x_api_key
    local expected_key = os.getenv("ADMIN_GATEWAY_API_KEY")

    if not expected_key or expected_key == "" then
        ngx.log(ngx.ERR, "ADMIN_GATEWAY_API_KEY environment variable not set")
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say('{"error": "Server misconfiguration: API key not set"}')
        ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
        return false
    end

    if not auth_header or auth_header ~= expected_key then
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.say('{"error": "Unauthorized. Provide valid X-Api-Key header."}')
        ngx.exit(ngx.HTTP_UNAUTHORIZED)
        return false
    end

    return true
end

local function rate_limit()
    local limit_key = "cmd_rate:" .. (ngx.var.remote_addr or "unknown")
    local shared = ngx.shared.cmd_rate_limit

    if not shared then
        ngx.log(ngx.WARN, "Shared dict 'cmd_rate_limit' not configured; skipping rate limit")
        return true
    end

    local current, err = shared:incr(limit_key, 1, 0, 60)
    if current and current > 30 then
        ngx.status = 429
        ngx.say('{"error": "Rate limit exceeded. Max 30 requests per minute."}')
        ngx.exit(429)
        return false
    end

    return true
end

